declare @c char(1), @d char(1)
select @c = char(253), @d = char(252)
select * into #t from dbo.FastBusiness$Function$System$Split(@@queryString, @c)
declare @ma_kh varchar(128), @ngay_ct1 smalldatetime, @ngay_ct2 smalldatetime, @ma_dvcs varchar(8000)

select @ma_dvcs = replace(data, @d, '''') from #t where id = 1
select @ngay_ct1 = data from #t where id = 2
select @ngay_ct2 = data from #t where id = 3

if @ma_dvcs = '' set @ma_dvcs = @@unit


select stt_rec, ma_nv, ho_nv, ten_nv into #hrnv from hrnv a
declare @queryWhereClause nvarchar(4000), @queryFormClause nvarchar(4000)
select @queryFormClause = 'hrccyccp m left join hrccctyccp a on a.stt_rec = m.stt_rec left join #hrnv b on a.stt_rec_nv = b.stt_rec left join hrcc c on a.ma_cc = c.ma_cc'
select @queryWhereClause = 'm.ma_dvcs = ''' + replace(rtrim(@ma_dvcs), '''', '''''') + ''' and m.status in (''2'', ''4'')'
